import React, { useEffect, useState } from 'react';
import { Table, Button, Popconfirm, Modal, Form, Input, message, Avatar, Space } from 'antd';
import { EditOutlined, DeleteOutlined, EyeOutlined } from '@ant-design/icons';

export default function ViewAllUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [editModalVisible, setEditModalVisible] = useState(false);
  const [form] = Form.useForm();

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const res = await fetch('/api/users', {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) setUsers(data);
      else message.error(data.message || 'Failed to fetch users');
    } catch (err) {
      message.error('Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsers(); }, []);

  const handleDelete = async (id) => {
    const token = localStorage.getItem('token');
    try {
      const res = await fetch(`/api/users/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) {
        message.success('User deleted');
        setUsers(users.filter(u => u._id !== id));
      } else {
        message.error(data.message || 'Failed to delete user');
      }
    } catch (err) {
      message.error('Failed to delete user');
    }
  };

  const handleEdit = (user) => {
    setEditingUser(user);
    setEditModalVisible(true);
    form.setFieldsValue({ ...user, password: '' });
  };

  const handleEditSubmit = async () => {
    try {
      const values = await form.validateFields();
      const token = localStorage.getItem('token');
      const res = await fetch(`/api/users/${editingUser._id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify(values),
      });
      const data = await res.json();
      if (res.ok) {
        message.success('User updated');
        setEditModalVisible(false);
        fetchUsers();
      } else {
        message.error(data.message || 'Failed to update user');
      }
    } catch (err) {
      message.error('Failed to update user');
    }
  };

  const columns = [
    { title: 'ID', dataIndex: '_id', key: '_id' },
    { title: 'Name', dataIndex: 'name', key: 'name' },
    { title: 'Email', dataIndex: 'email', key: 'email' },
    { title: 'Phone', dataIndex: 'phoneNumber', key: 'phoneNumber' },
    { title: 'NIC', dataIndex: 'nic', key: 'nic' },
    { title: 'Profile', dataIndex: 'profilePic', key: 'profilePic', render: url => url ? <Avatar src={url} /> : '-' },
    {
      title: 'Actions',
      key: 'actions',
      render: (_, user) => (
        <Space>
          <Button icon={<EyeOutlined />} onClick={() => window.open(`/user/${user._id}`, '_blank')}>View</Button>
          <Button icon={<EditOutlined />} onClick={() => handleEdit(user)}>Edit</Button>
          <Popconfirm title="Delete user?" onConfirm={() => handleDelete(user._id)} okText="Yes" cancelText="No">
            <Button icon={<DeleteOutlined />} danger>Delete</Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  return (
    <div style={{ maxWidth: 1200, margin: '0 auto', background: '#fff', borderRadius: 8, padding: 24, boxShadow: '0 2px 12px #e6f7ff' }}>
      <h2>All Users</h2>
      <Table columns={columns} dataSource={users} rowKey="_id" loading={loading} />
      <Modal
        title="Edit User"
        open={editModalVisible}
        onCancel={() => setEditModalVisible(false)}
        onOk={handleEditSubmit}
        okText="Save"
      >
        <Form form={form} layout="vertical">
          <Form.Item label="Name" name="name" rules={[{ required: true, message: 'Please enter Name' }]}> <Input /> </Form.Item>
          <Form.Item label="Email" name="email" rules={[{ required: true, type: 'email', message: 'Please enter Email' }]}> <Input /> </Form.Item>
          <Form.Item label="Phone Number" name="phoneNumber" rules={[{ required: true, message: 'Please enter Phone Number' }]}> <Input /> </Form.Item>
          <Form.Item label="NIC" name="nic" rules={[{ required: true, message: 'Please enter NIC' }]}> <Input /> </Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
